VALUES
  ('social-worker-moex-05740', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'essay', '社會工作者帶領一同志團體時，應有那些先備知識？於團體規劃時，應注意那些事
項？團體進行過程中，應運用那些團體工作技巧？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05741', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '大地震發生後，社會工作者進入災區陪伴受災戶、協助他們面對失去家人的悲痛及對震災的恐慌情緒， 這時最適合社會工作者採取的處遇模式是：', '["生態系統理論", "危機介入取向", "任務中心取向", "心理暨社會學派"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05742', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '一位未成年少女與陌生人發生一夜情後懷孕，他想詢問有關社會工作者墮胎的相關事宜，但社會工作者 是一位天主教徒，提出未出生的孩子也是生命，建議案主不應該輕言墮胎。此時，社會工作者所呈現的 倫理衝突是那方面？', '["個人價值與專業價值", "安全滿足與奮鬥刻苦", "案主需求與體系目標", "重視過程與強調結果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05743', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '當案主在結案階段，要求社會工作者在結案之後，非因追蹤計畫的持續接觸，而只是希望能持續當朋友， 維持聯繫或偶爾碰面來延續彼此的關係，以處理與社會工作者的分離。針對上述作法的敘述，下列何者 錯誤？', '["社會工作者與案主可能涉及雙重關係（dual relationship）的倫理議題", "這種循序漸進的關係結束策略，能使結案更為順利", "阻礙案主發展其他社會網絡的可能", "可被視為案主對於結案的負向情緒反應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05744', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「保密」的敘述，下列何者錯誤？', '["社會工作者應避免在不同的情境中，透漏案主的相關資訊（例如：在電梯中評論案主、與親友討論等）", "即使社會工作者被法院傳喚上法庭當證人，除非經過案主同意，也不能在法庭上洩漏案主的資料與紀錄", "當案主計畫或行為會嚴重傷害他人而告訴社會工作者時，他人的權利比案主資料保密的權利更優先", "社會工作者在運用電子科技蒐集、轉換或儲存案主隱私資料時，需更注意資料保密的處理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05745', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會支持系統（Social Support Systems, SSSs）的敘述，下列何者錯誤？', '["在案主的生活中，不同的社會支持系統扮演不同的角色，社會工作者須謹慎評估，並將其視為處遇服 務的一部分", "社會工作者可以運用生態圖的繪製，來了解案主的社會支持系統與網絡", "某些案主群（例如：老年人、被虐待或疏忽的兒童少年等）的社會支持系統是缺乏、不足的，特別需要 增強", "不論任何型態的社會支持系統，對於服務對象而言，都能帶來正向的影響與協助"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05746', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「家庭權力結構」是家庭評估（family assessment）其中一個重要面向，下列敘述何者錯誤？', '["社會工作者在評估家庭權力時，需考量家庭的權力分配者及動力", "家庭中的男性是主要的權力擁有者，女性雖然是家庭的重要角色，但是沒有權力的", "當家庭生命週期轉變、擁有權力者暫時性失業等內在或外在壓力改變時，家庭權力結構也會隨之轉變", "在評估與家庭有關的權力時，家庭歷史性事件有其重要的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05747', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在與非自願案主工作時，若能在會談過程中，給予他們對於自己問題看法的表達機會，並將 他們所關心的與社會工作者設定的服務目標整合，將有助於非自願案主的參與及改變。這個工作策略是：', '["同意命令", "讓我們來交易", "動機的一致性", "擺脫轉介來源所強加的限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05748', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社會工作理論中，強調人有能力解決自己的問題，但當問題太過複雜或為新問題時，案主一時無法釐 清問題脈絡，而出現生活困境。社會工作者在有限時間內，協助案主指認問題與優先處理的事務，來做 為處遇的焦點及策略。這個理論是：', '["任務中心取向", "危機介入取向", "優勢觀點", "充權觀點"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05749', 'social-worker', 'social-worker-moex-105-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那些是團體組成時，需考量的要素？①成員參與團體目標之同質性  ②任務性團體成員具有的不同', '["成員的年齡與性別等人口學因素", "團體的大小  ⑤團體的結構", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "0637ff9598cc", "answer_pdf_sha1": "e5cfd3dd419e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
